module top_module(
    input clk, rst,
    output reg [3:0] counter_output
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@ (posedge clk or posedge dbg_halt) begin 
        if( rst | counter_output == 4'b1001)
            counter_output <= 4'b0000;
        else
            counter_output <= counter_output + 1;
    end
endmodule
